package main

import (
    "net/http"
    "time"

    "github.com/prometheus/client_golang/prometheus"
    "github.com/prometheus/client_golang/prometheus/promauto"
    "github.com/prometheus/client_golang/prometheus/promhttp"
)

var (
    requestDuration = promauto.NewHistogramVec(
        prometheus.HistogramOpts{
            Name:    "http_request_duration_seconds",
            Help:    "Histogram of HTTP request durations",
            Buckets: prometheus.DefBuckets,
        },
        []string{"user_id", "endpoint", "status_code"},
    )

    requestCount = promauto.NewCounterVec(
        prometheus.CounterOpts{
            Name: "http_requests_total",
            Help: "Total number of HTTP requests",
        },
        []string{"user_id", "endpoint", "status_code"},
    )

    activeUsers = promauto.NewGaugeVec(
        prometheus.GaugeOpts{
            Name: "active_users",
            Help: "Number of active users",
        },
        []string{"user_id"},
    )

    userRequests = promauto.NewCounterVec(
        prometheus.CounterOpts{
            Name: "user_requests_total",
            Help: "Total number of requests per user",
        },
        []string{"user_id"},
    )

    userErrors = promauto.NewCounterVec(
        prometheus.CounterOpts{
            Name: "user_errors_total",
            Help: "Total number of errors per user",
        },
        []string{"user_id", "error_type"},
    )
)

func main() {
    http.Handle("/metrics", promhttp.Handler())
    
    http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
        userID := r.URL.Query().Get("user_id")
        if userID == "" {
            userID = "unknown"
        }
        
        endpoint := r.URL.Path
        statusCode := "200"
        
        start := time.Now()
        
        activeUsers.WithLabelValues(userID).Inc()
        userRequests.WithLabelValues(userID).Inc()
        
        defer func() {
            duration := time.Since(start).Seconds()
            requestDuration.WithLabelValues(userID, endpoint, statusCode).Observe(duration)
            requestCount.WithLabelValues(userID, endpoint, statusCode).Inc()
            activeUsers.WithLabelValues(userID).Dec()
        }()
        
        // Simulate some work
        time.Sleep(10 * time.Millisecond)
        
        w.WriteHeader(http.StatusOK)
        w.Write([]byte("Hello World"))
    })
    
    http.HandleFunc("/error", func(w http.ResponseWriter, r *http.Request) {
        userID := r.URL.Query().Get("user_id")
        if userID == "" {
            userID = "unknown"
        }
        
        endpoint := r.URL.Path
        errorType := "internal_error"
        
        userErrors.WithLabelValues(userID, errorType).Inc()
        
        w.WriteHeader(http.StatusInternalServerError)
        w.Write([]byte("Internal Server Error"))
    })
    
    http.ListenAndServe(":8080", nil)
}